example.code:
ACTION = {
    "RETRY_LATER":      lambda env: ("retry", min(max(env.get("retry_after_seconds", 5), 1), 300)),
    "CHECK_INPUT":      lambda env: ("send_to_model", None),
    "TRY_ALTERNATIVE":  lambda env: ("send_to_model", None),
    "REPORT_TO_USER":   lambda env: ("halt", env),
    "NEEDS_AUTH":       lambda env: ("auth", env),
}

def dispatch(error_envelope, retries_left):
    hint = error_envelope["recoveryHint"]
    kind, payload = ACTION[hint](error_envelope)
    if kind == "retry" and retries_left > 0:
        return ("sleep_then_retry", payload)
    if kind == "retry":
        return ("send_to_model", error_envelope)  # exhausted
    return (kind, payload)
